import { env } from '@nordic/env';

import { NordicRenderingContextError } from '../../common/error';
import { getRenderingCriticalCss } from '../getters';
import { validateIfHeadersSent } from '../utils/validations';
import {
  CRITICAL_COOKIE_SEPARATOR,
  CRITICAL_COOKIE_MAX_LENGTH,
  CRITICAL_COOKIES_ERROR_MESSAGE,
} from './constants';
import { setCookie } from './utils';

export function setRenderingCriticalCssCookie() {
  const { name, path, values } = getRenderingCriticalCss();

  if (!values.size) {
    return;
  }

  values.add(env.VERSION);

  const value = Array.from(values).join(CRITICAL_COOKIE_SEPARATOR);

  if (value.length <= CRITICAL_COOKIE_MAX_LENGTH) {
    setCookie({ name, value, path });

    return;
  }

  if (__DEV__) {
    throw new NordicRenderingContextError(
      'The value for critical styles cookie is too long,' +
        ` the maximum length is ${CRITICAL_COOKIE_MAX_LENGTH} characters. Value: ${value}`,
    );
  }
}

export function setRenderingCriticalCssValue(value: string) {
  if (validateIfHeadersSent(CRITICAL_COOKIES_ERROR_MESSAGE)) {
    return false;
  }

  const { values } = getRenderingCriticalCss();
  const changed = !values.has(value);

  if (changed) {
    values.add(value);
  }

  return changed;
}
